import logo from './logo.svg';
import './App.css';
import { Component } from 'react';

class App extends Component{

  constructor(){
    super();

    this.state = {
      monsters :[
        {
          id : '1',
          name : 'Sagar'
        },
        {
          id : '2',
          name : 'Ashwini'
        },
        {
          id : '3',
          name : 'Ovee'
        },
        {
          id : '4',
          name : 'Mammy'
        }
      ]
    }; 
  }

  render() {
    return (
      <div className="App">
        {
          this.state.monsters.map(monsters => (
              <p key = {monsters.id}>{monsters.name}</p> 
          ))
        }
      </div>
    );
  }

}


export default App;
